// Preparar contexto completo para el agente
const telegram = $input.first().json;
const memory = $('Cargar Memoria').first().json;

const chatId = telegram.message?.chat?.id;
const userName = telegram.message?.from?.first_name || 'Usuario';
const userMessage = telegram.message?.text;
const history = memory?.history || [];

// Formatear historial legible
let historyText = 'Sin historial previo.';
if (history.length > 0) {
  historyText = history.slice(-10).map(msg => 
    `${msg.role === 'user' ? '👤 Usuario' : '🤖 Refubot'}: ${msg?.content}`
  ).join('\n\n');
}

// Fecha actual en formato peruano
const now = new Date();
const peruDate = new Intl.DateTimeFormat('es-PE', {
  timeZone: 'America/Lima',
  year: 'numeric',
  month: '2-digit',
  day: '2-digit'
}).format(now);

return [{
  chatId: chatId,
  userName: userName,
  userMessage: userMessage,
  history: history,
  historyText: historyText,
  currentDate: peruDate,
  timezone: 'America/Lima'
}];

const negocios = [
  'Quién pidió pollo', 'Puerto Mancora', 'Patio Cavenecia',
  'Caja China Criolla', 'Bros', 'Belgofre', 'Limanesas',
  'Saltao', 'Vikinga', 'Bodega Turca', 'La 22', 'Taqueado',
  'Choza de la Anaconda', 'MR SMASH', 'Sisa Cafe', 'Hanzo',
  'La Victoria', 'Curich', 'Anticuching', 'Bar Refugio'
];

const busqueda = ($input.first().json.query || '').toLowerCase();
const encontrado = negocios.find(n => 
  n.toLowerCase().includes(busqueda) || 
  busqueda.includes(n.toLowerCase())
);

if (encontrado) {
  return { existe: true, nombre_exacto: encontrado };
} else {
  return { 
    existe: false, 
    sugerencias: negocios.slice(0, 5).join(', ')
  };
}

// Actualizar memoria conversacional
const context = $('Preparar Contexto').first().json;
const agentOutput = $input.first().json;

const userMsg = { role: 'user', content: context.userMessage };
const assistantMsg = { 
  role: 'assistant', 
  content: agentOutput.output || agentOutput.text || 'Sin respuesta'
};

// Mantener últimas 20 interacciones
const newHistory = [
  ...context.history,
  userMsg,
  assistantMsg
].slice(-20);

return [{
  chatId: context.chatId,
  newHistory: newHistory,
  responseText: assistantMsg.content
}];

// Manejo inteligente de errores
const error = $input.first().json.error || {};
const errorMsg = (error.message || '').toLowerCase();
let response;

if (errorMsg.includes('syntax') || errorMsg.includes('invalid')) {
  response = '🤔 Hubo un problema al generar la consulta SQL. Por favor, reformula tu pregunta.';
} 
else if (errorMsg.includes('not found') || errorMsg.includes('no existe')) {
  response = '😅 No encontré ese elemento. Verifica el nombre del negocio o las fechas.';
} 
else if (errorMsg.includes('permission') || errorMsg.includes('403')) {
  response = '🔒 No tengo permisos en este momento. El equipo técnico ha sido notificado.';
} 
else if (errorMsg.includes('timeout') || errorMsg.includes('rate limit')) {
  response = '🚦 Sistema ocupado. Intenta de nuevo en 1 minuto por favor.';
} 
else if (errorMsg.includes('connection')) {
  response = '🔌 Error de conexión temporal. Reintenta en unos segundos.';
} 
else {
  response = '😞 Error inesperado. Por favor, intenta reformular tu consulta.';
}

return [{
  chatId: $('Preparar Contexto').first().json.chatId,
  errorMessage: response
}];

